public class SimpleKdcServer extends KdcServer { private static final Logger LOG = LoggerFactory . getLogger ( SimpleKdcServer . class ) ; private final KrbClient krbClnt ; private LocalKadmin kadmin ; private Krb5Conf krb5Conf ; private File workDir ; private KrbPkinitClient pkinitClient ; private KrbTokenClient tokenClient ; public SimpleKdcServer ( ) throws KrbException { this ( new KrbConfig ( ) ) ; setKdcRealm ( "EXAMPLE.COM" ) ; setKdcHost ( "localhost" ) ; setKdcPort ( NetworkUtil . getServerPort ( ) ) ; } public SimpleKdcServer ( KdcConfig kdcConfig , BackendConfig backendConfig ) throws KrbException { super ( kdcConfig , backendConfig ) ; this . krbClnt = new KrbClient ( new KrbConfig ( ) ) ; setKdcRealm ( "EXAMPLE.COM" ) ; setKdcHost ( "localhost" ) ; setKdcPort ( NetworkUtil . getServerPort ( ) ) ; } public SimpleKdcServer ( KrbConfig krbConfig ) { super ( ) ; this . krbClnt = new KrbClient ( krbConfig ) ; } public SimpleKdcServer ( File confDir , KrbConfig krbConfig ) throws KrbException { super ( confDir ) ; this . krbClnt = new KrbClient ( krbConfig ) ; } public synchronized void setWorkDir ( File workDir ) { this . workDir = workDir ; } public synchronized File getWorkDir ( ) { return workDir ; } @ Override public synchronized void setKdcRealm ( String realm ) { super . setKdcRealm ( realm ) ; krbClnt . setKdcRealm ( realm ) ; } @ Override public synchronized void setKdcHost ( String kdcHost ) { super . setKdcHost ( kdcHost ) ; krbClnt . setKdcHost ( kdcHost ) ; } @ Override public synchronized void setKdcTcpPort ( int kdcTcpPort ) { super . setKdcTcpPort ( kdcTcpPort ) ; krbClnt . setKdcTcpPort ( kdcTcpPort ) ; setAllowTcp ( true ) ; } @ Override public synchronized void setAllowUdp ( boolean allowUdp ) { super . setAllowUdp ( allowUdp ) ; krbClnt . setAllowUdp ( allowUdp ) ; } @ Override public synchronized void setAllowTcp ( boolean allowTcp ) { super . setAllowTcp ( allowTcp ) ; krbClnt . setAllowTcp ( allowTcp ) ; } @ Override public synchronized void setKdcUdpPort ( int kdcUdpPort ) { super . setKdcUdpPort ( kdcUdpPort ) ; krbClnt . setKdcUdpPort ( kdcUdpPort ) ; setAllowUdp ( true ) ; } @ Override public synchronized void init ( ) throws KrbException { super . init ( ) ; kadmin = new LocalKadminImpl ( getKdcSetting ( ) , getIdentityService ( ) ) ; kadmin . createBuiltinPrincipals ( ) ; try { krb5Conf = new Krb5Conf ( this ) ; krb5Conf . initKrb5conf ( ) ; } catch ( IOException e ) { throw new KrbException ( "Failed to make krb5.conf" , e ) ; } } @ Override public synchronized void start ( ) throws KrbException { super . start ( ) ; krbClnt . init ( ) ; } public synchronized KrbClient getKrbClient ( ) { return krbClnt ; } public synchronized KrbPkinitClient getPkinitClient ( ) { if ( pkinitClient == null ) { pkinitClient = new KrbPkinitClient ( krbClnt ) ; } return pkinitClient ; } public synchronized KrbTokenClient getTokenClient ( ) { if ( tokenClient == null ) { tokenClient = new KrbTokenClient ( krbClnt ) ; } return tokenClient ; } public synchronized LocalKadmin getKadmin ( ) { return kadmin ; } public synchronized void createPrincipal ( String principal ) throws KrbException { kadmin . addPrincipal ( principal ) ; } public synchronized void createPrincipal ( String principal , String password ) throws KrbException { kadmin . addPrincipal ( principal , password ) ; } public synchronized void createPrincipals ( String ... principals ) throws KrbException { for ( String principal : principals ) { kadmin . addPrincipal ( principal ) ; } } public synchronized void createAndExportPrincipals ( File keytabFile , String ... principals ) throws KrbException { createPrincipals ( principals ) ; exportPrincipals ( keytabFile ) ; } public synchronized void deletePrincipals ( String ... principals ) throws KrbException { for ( String principal : principals ) { deletePrincipal ( principal ) ; } } public synchronized void deletePrincipal ( String principal ) throws KrbException { kadmin . deletePrincipal ( principal ) ; } public synchronized void exportPrincipals ( File keytabFile ) throws KrbException { kadmin . exportKeytab ( keytabFile ) ; } public synchronized void exportPrincipal ( String principal , File keytabFile ) throws KrbException { kadmin . exportKeytab ( keytabFile , principal ) ; } @ Override public synchronized void stop ( ) throws KrbException { super . stop ( ) ; try { krb5Conf . deleteKrb5conf ( ) ; } catch ( IOException e ) { LOG . info ( "Fail to delete krb5 conf. " + e ) ; } } }